sysevent_script_action.script:
(function() {
    var p;
    try { p = JSON.parse(event.parm1); }
    catch (pe) { gs.error('[VA-MIGRATE] bad payload: ' + event.parm1); return; }

    gs.info('[VA-MIGRATE] starting ' + p.table + '/' + p.sysId);
    var startMs = new GlideDateTime().getNumericValue();

    try {
        var engine = new DM_MigrationCore();
        engine.SOURCE_URL  = p.url;
        engine.SOURCE_USER = p.user;
        engine.SOURCE_PSWD = p.pass;
        engine.DEBUG       = false;

        var targetSysId = engine.migrateWithDependencies(p.table, p.sysId, 0);
        var secs = Math.round((new GlideDateTime().getNumericValue() - startMs) / 1000);
        var s = engine.stats || {};

        if (targetSysId) {
            gs.info('[VA-MIGRATE] ✔ DONE in ' + secs + 's — ' + p.table + '/' + p.sysId +
                    ' → ' + targetSysId +
                    ' | inserted=' + (s.inserted || 0) +
                    ' updated='  + (s.updated  || 0) +
                    ' failed='   + (s.failed   || 0) +
                    ' | reminder: run the Global number post-pass for numbers');
        } else {
            gs.error('[VA-MIGRATE] ✗ engine returned no target sys_id for ' +
                     p.table + '/' + p.sysId + ' after ' + secs + 's');
        }
    } catch (e) {
        gs.error('[VA-MIGRATE] ✗ threw: ' + ((e && e.message) ? e.message : String(e)) +
                 ' | ' + (e && e.stack ? e.stack : ''));
    }
})();
